-- ---------------------------------------------------------------- basics-of-investing
insert into public.lessons
  (course_id, slug, title, description, xp_reward, sort_order, unit, content, summary_points)
select
  id,
  'basics-of-investing',
  'The basics of investing',
  'Plant money today, pick fruit for decades — starting with $5.',
  25,
  7,
  4,
  $json$[{"type":"material","title":"Plant it, don't just park it","body":"Spend $10 on a game skin and it's gone forever. Invest that $10 and it has a shot at becoming $15, $20, or more — because investing means using money today to grow more money tomorrow.\n\nThink of it like planting a tree. You bury a seed (your cash), water it (add a little regularly), and wait. Years later it's dropping fruit — money your money made — while you do absolutely nothing.","image":"/illustrations/investing-tree.svg","imageAlt":"A money tree growing from a planted seed"},{"type":"material","title":"Why not just save?","body":"Savings accounts keep money safe, but barely grow it:\n- $100 saved at 1% interest → $101 after a year\n- $100 invested in the stock market → historically around 7–10% a year ON AVERAGE, so maybe $108\n\nThe catch: \"on average\" hides wild swings. Some years stocks jump 20%, some years they drop 20%. Investing trades a smooth ride for a faster one — which is why it's for money you won't need soon."},{"type":"true_false","prompt":"Investing in the stock market is basically gambling.","answer":false,"explanation":"Gambling is a bet where the odds are against you. Owning diversified investments for years means owning real businesses that grow — though betting everything on one hot stock IS closer to gambling."},{"type":"multiple_choice","prompt":"Why invest at all when savings accounts are safer?","options":["Investing is guaranteed to beat savings","Banks charge fees on savings accounts","Investing has much higher growth potential over time","Savings accounts are actually riskier"],"correctIndex":2,"explanation":"No guarantees — markets swing — but historically investments have grown far faster than savings. You're trading some safety for growth."},{"type":"material","title":"The big three","body":"Almost every investment you'll meet is one of these:\n- **Stocks** — you own a tiny slice of a company. Nike does well, your slice is worth more. Some even pay you a cut of profits (dividends).\n- **Bonds** — you LEND money to a company or government, and they pay you back with interest. Slower, steadier.\n- **Mutual funds & ETFs** — baskets holding many stocks and bonds at once, so one company's bad year can't wreck you."},{"type":"match_pairs","prompt":"Match each investing word to what it really is.","pairs":[{"left":"Stock","right":"Owning a slice of a company"},{"left":"Bond","right":"A loan you give, repaid with interest"},{"left":"Mutual fund","right":"A basket of many investments"},{"left":"Dividend","right":"Profit a company shares with you"}]},{"type":"fill_blank","prompt":"A $1,000 government bond pays 3% simple yearly interest. After 5 years you collect $___ in total.","answer":"1150","accept":["$1,150","1,150","$1150"],"hint":"That's $30 a year, five times, plus your $1,000 back.","explanation":"$1,000 × 3% = $30 a year. Five years = $150 in interest, plus your original $1,000 back = $1,150."},{"type":"material","title":"Risk and reward: a package deal","body":"There's no prize without a price:\n- **High risk, high potential reward** — individual stocks, crypto. Could double, could halve.\n- **Low risk, low reward** — government bonds, savings. Slow, steady, boring.\n\nThe pro move isn't picking one extreme — it's **diversifying**: spreading money across different investments so one flop can't take you down. That's exactly what funds do for you automatically."},{"type":"categorize","prompt":"Higher risk or lower risk?","categories":["Higher risk","Lower risk"],"items":[{"text":"Shares of one single company","category":0},{"text":"Government bonds","category":1},{"text":"Cryptocurrency","category":0},{"text":"A savings account","category":1},{"text":"A stranger's \"guaranteed 10x\" coin","category":0},{"text":"A diversified index fund","category":1}]},{"type":"multiple_choice","prompt":"What's the smart move for long-term money?","context":"Three months after you start investing, the market drops 15%. Your $500 is now $425.","options":["Sell everything before it falls further","Stay invested — markets have recovered from every crash so far","Move it all into crypto to win it back fast","Sell now, wait for the bottom, buy back in"],"correctIndex":1,"explanation":"Selling in a panic locks in the loss. Historically, investors who stayed put rode the recovery — and timing the bottom almost never works."},{"type":"material","title":"Time is your superpower","body":"Compound growth means your earnings start earning. It's a snowball rolling downhill: tiny at first, unstoppable later.\n\n$50 a month at about 7% average growth:\n- Start at 18 → roughly $230,000 by 65\n- Start at 30 → roughly $100,000 by 65\n\nSame habit, same monthly amount — starting 12 years earlier more than doubles the pot. The biggest investing advantage you will ever have is being young."},{"type":"slider_estimate","prompt":"You invest $100 once at 7% average growth and ignore it for 30 years. Slide to where it lands.","min":100,"max":1000,"step":20,"answer":760,"tolerance":40,"unitPrefix":"$","explanation":"At 7%, money doubles roughly every 10 years: $100 → $200 → $400 → about $760 after 30. The last decade earns more than the first two combined."},{"type":"tap_word","instructions":"One word turns this into terrible advice. Tap it.","sentence":"Putting all your eggs in one basket is the safest way to invest.","wrongWord":"safest","correctWord":"riskiest","explanation":"One basket means one bad drop breaks everything. Diversification exists so a single flop can't wipe you out."},{"type":"material","title":"Starting with pocket change","body":"You don't need $10,000 — you need a habit:\n- **Micro-investing apps** let you start with $5–$10\n- **Low-cost index funds and ETFs** buy you the whole market in one move\n- **Automate it** — small and consistent beats big and occasional\n\nTwo rules before your first dollar goes in: build a small emergency fund FIRST (so a surprise bill never forces you to sell), and treat anything promising fast guaranteed riches as a scam — because it is."},{"type":"true_false","prompt":"You should invest your emergency fund so it grows instead of sitting in savings.","answer":false,"explanation":"Emergency money must be there the day you need it. If a crash and a car repair hit the same week, an invested emergency fund forces you to sell at a loss."},{"type":"decision_path","title":"The $1,000 Year","intro":"You've got $1,000 and 12 months. Beat the market's mood swings and end the year ahead.","stat":{"name":"Portfolio","emoji":"💼","start":1000},"steps":[{"situation":"January. Time to put your $1,000 to work. How do you spread it?","options":[{"text":"All-in on one hot tech stock","delta":-80,"feedback":"It spiked, then sank. One company means one bad headline can sink you."},{"text":"Split it: stocks, bonds, and an index fund","delta":60,"feedback":"Diversified. No single flop can take you out — and the mix still grows.","best":true},{"text":"Keep it all in cash for now","delta":-20,"feedback":"Zero risk, zero growth — and inflation quietly shrank what your cash can buy."}]},{"situation":"April. Tech boom! The stock slice of your portfolio jumps 20%.","options":[{"text":"Sell everything and lock in the win","delta":20,"feedback":"You banked a small win, but now you're out of the market — and re-entering is scary."},{"text":"Hold your plan, trim just a little profit","delta":120,"feedback":"You stayed invested for the growth and skimmed a bit of profit. Balanced.","best":true},{"text":"Move everything into tech — it's clearly winning","delta":-60,"feedback":"Chasing a spike is how people buy at the top. It cooled off right after."}]},{"situation":"August. Market crash — stocks plunge 15% in a week and your feed is pure panic.","options":[{"text":"Sell it all before it gets worse","delta":-150,"feedback":"You locked in the loss. The market recovered within months; your sold shares didn't."},{"text":"Stay invested, keep monthly contributions going","delta":80,"feedback":"Every crash so far has eventually recovered — and you bought the dip on autopilot.","best":true},{"text":"Stop looking AND stop contributing for a while","delta":-10,"feedback":"Not selling helps, but pausing contributions means skipping the discount aisle."}]},{"situation":"October. Interest rates rise: bonds now pay more, and stocks dip 5%.","options":[{"text":"Dump all stocks, go 100% bonds","delta":-40,"feedback":"Overcorrection. You traded long-term growth for a small bump in safety."},{"text":"Nudge a little more into bonds, keep the mix","delta":40,"feedback":"A light rebalance keeps your plan on target without abandoning growth.","best":true},{"text":"Change nothing, never look again","delta":0,"feedback":"Doing nothing beats panicking, but a small rebalance would've kept your mix on plan."}]},{"situation":"December. Your car needs a $200 repair — this can't wait.","options":[{"text":"Sell stocks (still recovering from the crash)","delta":-280,"feedback":"You sold low and turned the crash into a real, permanent loss. Ouch."},{"text":"Withdraw from your bond slice","delta":-200,"feedback":"Safer assets are your shock absorber — stable value, no fire sale required.","best":true},{"text":"Credit card at 24% APR, leave investments alone","delta":-250,"feedback":"That interest costs more than your investments earn. The math loses every time."}]}],"outro":"Finish above $1,000 and you beat a chaotic year. The winning moves were boring on purpose: diversify, hold through the panic, rebalance lightly, and let bonds absorb the emergencies."}]$json$::jsonb,
  $json$["Investing puts money to work; spending makes it vanish","Stocks = owning, bonds = lending, funds = a basket of both","Stocks return about 7–10% a year on average — with big swings","Starting at 18 instead of 30 can roughly double your final pot","Emergency fund first, then small automatic investments"]$json$::jsonb
from public.courses where slug = 'personal-finance'
on conflict (course_id, slug) do update set
  title = excluded.title,
  description = excluded.description,
  xp_reward = excluded.xp_reward,
  sort_order = excluded.sort_order,
  unit = excluded.unit,
  content = excluded.content,
  summary_points = excluded.summary_points;

-- ---------------------------------------------------------------- risk-and-reward
insert into public.lessons
  (course_id, slug, title, description, xp_reward, sort_order, unit, content, summary_points)
select
  id,
  'risk-and-reward',
  'Risk and reward: the balancing act',
  'Match every dollar to its deadline — and keep your cool when markets wobble.',
  25,
  8,
  4,
  $json$[{"type":"material","title":"The balancing act","body":"Investing runs on one trade: **risk** (the chance you lose money) against **reward** (the growth you might get). They're welded together — you can't crank one without the other.\n\nPicture a skate ramp. The higher you climb, the bigger the trick — and the harder the fall. Stocks are the tall ramp: they can double your money or drop hard. Bonds are the mellow ramp: small tricks, soft landings.\n\nStrategy is just choosing your ramp on purpose.","image":"/illustrations/needs-wants.svg","imageAlt":"A two-pan balance scale, weighing risk against reward"},{"type":"tap_word","instructions":"One word breaks this rule. Tap it.","sentence":"The bigger the potential reward, the smaller the risk you're usually taking.","wrongWord":"smaller","correctWord":"bigger","explanation":"Risk and reward scale together. Anyone promising big rewards with tiny risk is selling something — usually to you."},{"type":"material","title":"Diversification: don't bet the backpack","body":"Diversification means spreading money across different investments so one disaster can't flatten you.\n\nSay you split $1,000: $500 stocks, $300 bonds, $200 mutual fund. A rough month hits — stocks drop 20%, bonds gain 3%, the fund gains 5%:\n- Stocks: −$100\n- Bonds: +$9\n- Fund: +$10\n\nNet damage: −$81. All-in on stocks, that same month costs you $200. Same crash, less than half the bruise."},{"type":"fill_blank","prompt":"In that rough month, the $500 stock slice alone lost $___.","answer":"100","accept":["$100","100$"],"explanation":"$500 × 20% = $100. The bonds and fund clawing back $19 of it is diversification doing its job."},{"type":"multiple_choice","prompt":"What does a strategist do?","context":"Stocks drop 12% in a week. Your goal is 20+ years away, and your group chat is screaming \"SELL.\"","options":["Sell now, buy back in when it feels safe","Stay invested and keep the monthly auto-invest running","Move everything into crypto for a fast rebound","Check the portfolio hourly until it recovers"],"correctIndex":1,"explanation":"With decades of runway, dips are discounts. \"Buy back when it feels safe\" usually means buying back at a higher price."},{"type":"material","title":"Age is an asset","body":"The younger you are, the more risk you can afford — not because you're braver, but because you have TIME. A crash at 18 has decades to recover. A crash at 60 hits right before the money is needed.\n\nTypical tilts:\n- **18-year-old:** 70% stocks, 20% bonds, 10% funds — growth mode\n- **50-year-old:** 30% stocks, 50% bonds, 20% funds — protect mode\n\nYour mix should slowly get safer as your deadline gets closer."},{"type":"match_pairs","prompt":"Match each investor profile to its typical mix.","pairs":[{"left":"Conservative","right":"60% bonds, 20% funds, 20% stocks"},{"left":"Balanced","right":"40% stocks, 30% bonds, 30% funds"},{"left":"Aggressive","right":"70% stocks, 20% funds, 10% bonds"}]},{"type":"true_false","prompt":"An 18-year-old can usually afford a more stock-heavy, risky mix than a 50-year-old.","answer":true,"explanation":"Time is the recovery tool. Decades of runway let young investors ride out crashes that would derail someone close to their goal."},{"type":"material","title":"Match money to its deadline","body":"Before you pick an investment, ask the money one question: WHEN do I need you back?\n- **1–3 years** (laptop, summer trip) → safer spots: savings, bonds. A crash the month before you buy would hurt too much.\n- **5+ years** (college, a car, someday-retirement) → growth assets: stocks, funds. There's time to recover from dips.\n\nThe mistake isn't picking risky or safe — it's mismatching: gambling next year's laptop money, or parking 40-year retirement money in a savings account."},{"type":"categorize","prompt":"Where does this money belong?","categories":["Safer assets","Growth assets"],"items":[{"text":"Laptop fund you'll spend next year","category":0},{"text":"Retirement money, 45 years away","category":1},{"text":"Summer trip 18 months out","category":0},{"text":"College fund, 10 years away","category":1},{"text":"Your emergency fund","category":0},{"text":"Dream-travel fund for your 30s","category":1}]},{"type":"multiple_choice","prompt":"What's the move?","context":"Your target mix is 60% stocks. After a huge rally, stocks have swollen to 80% of your portfolio.","options":["Nothing — let the winners keep winning","Sell ALL the stocks and lock in every gain","Sell some stocks and top up bonds and funds back toward 60%","Buy even more stocks — momentum is real"],"correctIndex":2,"explanation":"At 80% you're carrying far more risk than you chose. Rebalancing quietly sells high and buys low — on schedule, not on emotion."},{"type":"material","title":"Volatility, the wiggle","body":"Volatility is how violently a price wiggles. Stocks wiggle hard — up 3% Tuesday, down 4% Friday. Bonds barely twitch.\n\nHere's the secret: short-term wiggles are NOISE if your goal is years away. The investors who get hurt are the ones who stare at every wiggle and react to it.\n\nSo no, don't check your portfolio every day. Check it like you check your height — occasionally, expecting slow change."},{"type":"true_false","prompt":"Checking your portfolio every day helps a long-term investor make better decisions.","answer":false,"explanation":"Daily noise triggers panic moves, and panic moves are what actually lose money. Long-term plans need occasional check-ins, not surveillance."},{"type":"slider_estimate","prompt":"Crash test: your $800 stock slice drops 15%. Slide to what it's worth now.","min":400,"max":800,"step":20,"answer":680,"tolerance":40,"unitPrefix":"$","explanation":"15% of $800 is $120, leaving $680. Feel that sting in practice mode — so the real thing doesn't shake you into selling."},{"type":"material","title":"Your first strategy, five moves","body":"Every solid starter strategy is the same five moves:\n- **Know your risk tolerance** — how big a dip can you watch without selling?\n- **Set goals with dates** — the date picks the asset\n- **Diversify** — stocks, bonds, funds; never one basket\n- **Start small and automate** — even $5–$10 a week builds the habit\n- **Review occasionally** — rebalance when life or markets shift\n\nAnd before move one: emergency fund in savings. Practice apps with fake money make great training wheels."},{"type":"order_steps","prompt":"Build your first investment strategy. Put the moves in order.","steps":["Figure out your risk tolerance","Set goals with timelines","Diversify across stocks, bonds, and funds","Start small with automatic deposits","Review and rebalance now and then"],"explanation":"Know yourself, then your targets, then spread the risk, then start the habit — and check in occasionally. Each step shapes the next one."},{"type":"decision_path","title":"The Goal Matcher","intro":"Different pots of money, one year of market chaos. Match each move to the right goal and rack up strategy points.","stat":{"name":"Strategy score","emoji":"🎯","start":0},"steps":[{"situation":"You're saving for a laptop you'll buy NEXT YEAR. Where does that money live?","options":[{"text":"Stocks — squeeze out extra growth","delta":-20,"feedback":"A 15% dip next spring could shrink the fund right before checkout. Wrong ramp for a short trip."},{"text":"Savings or short-term bonds","delta":25,"feedback":"Money with a near deadline belongs somewhere boring. Boring is the feature.","best":true},{"text":"Crypto — get there faster","delta":-30,"feedback":"Could double, could halve. Next-year money can't survive a \"could halve.\""}]},{"situation":"Now your long-term pot — 10+ years until you touch it. How do you tilt it?","options":[{"text":"Growth-heavy: mostly stocks and funds, some bonds","delta":25,"feedback":"Decades of runway means time to outride every dip. Growth mode is right here.","best":true},{"text":"All bonds — keep it perfectly safe","delta":-10,"feedback":"Safe from crashes, but also safe from growing. Over decades, that costs a fortune."},{"text":"100% in the one company you love","delta":-25,"feedback":"That's loyalty, not strategy. One bad earnings call shouldn't decide your future."}]},{"situation":"Markets drop 10% in a month. Your long-term pot is down and your stomach hurts.","options":[{"text":"Sell before it gets worse","delta":-25,"feedback":"You sold low and turned a paper dip into a real loss."},{"text":"Stick to the plan, keep auto-investing","delta":25,"feedback":"The deadline is decades away — this dip is a discount, not a disaster.","best":true},{"text":"Borrow money to buy MORE of the dip","delta":-15,"feedback":"Right instinct, wrong fuel. Investing borrowed money turns a dip into a debt problem."}]},{"situation":"A year of gains later, stocks have grown to 85% of your portfolio. Your target was 60%.","options":[{"text":"Let it ride — never touch a winner","delta":-15,"feedback":"Your risk quietly ballooned past what you chose. The mix drifted; your plan didn't."},{"text":"Rebalance: trim stocks, top up bonds and funds","delta":25,"feedback":"Sell a little high, buy a little low, sleep fine. That's maintenance, not market timing.","best":true},{"text":"Sell ALL the stocks — gains are gains","delta":-10,"feedback":"Overcorrected. Locking the whole pot out of growth mode isn't balance either."}]}],"outro":"A perfect run scores 100. Notice the pattern: the right answer was never the exciting one — it was matching every dollar to its deadline."}]$json$::jsonb,
  $json$["Risk and reward scale together — no big gains without big swings","Diversify so one bad bet bruises instead of breaks","Match money to deadlines: 1–3 years safe, 5+ years growth","More runway = more risk you can afford; tilt safer as goals get close","Rebalance occasionally — and stop checking daily"]$json$::jsonb
